import{_ as e,o as t,c as r,ag as o}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"常见问题","description":"关于 bamdra-openclaw-memory 的部署、使用和边界说明。","frontmatter":{"title":"常见问题","description":"关于 bamdra-openclaw-memory 的部署、使用和边界说明。"},"headers":[],"relativePath":"zh/guide/faq.md","filePath":"zh/guide/faq.md","lastUpdated":null}'),i={name:"zh/guide/faq.md"};function l(h,a,n,d,s,c){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="需要额外的缓存服务吗" tabindex="-1">需要额外的缓存服务吗？ <a class="header-anchor" href="#需要额外的缓存服务吗" aria-label="Permalink to &quot;需要额外的缓存服务吗？&quot;">​</a></h2><p>不需要。对大多数团队来说，SQLite 加默认的进程内缓存已经足够。</p><h2 id="这个产品只适合开发者吗" tabindex="-1">这个产品只适合开发者吗？ <a class="header-anchor" href="#这个产品只适合开发者吗" aria-label="Permalink to &quot;这个产品只适合开发者吗？&quot;">​</a></h2><p>不是。安装层面会更偏技术，但它解决的问题属于更广泛的产品、运营、研发和知识工作协作场景。</p><h2 id="它最擅长记住什么" tabindex="-1">它最擅长记住什么？ <a class="header-anchor" href="#它最擅长记住什么" aria-label="Permalink to &quot;它最擅长记住什么？&quot;">​</a></h2><p>它最擅长的是稳定事实、话题分支、紧凑摘要以及中断后的连续性恢复。</p><h2 id="什么不应该直接存进去" tabindex="-1">什么不应该直接存进去？ <a class="header-anchor" href="#什么不应该直接存进去" aria-label="Permalink to &quot;什么不应该直接存进去？&quot;">​</a></h2><p>不要把长期记忆当成原始 secret 的堆放区。敏感信息仍应遵循你的常规安全规范。</p><h2 id="重启以后还能恢复吗" tabindex="-1">重启以后还能恢复吗？ <a class="header-anchor" href="#重启以后还能恢复吗" aria-label="Permalink to &quot;重启以后还能恢复吗？&quot;">​</a></h2><p>可以。基于 SQLite 的重启恢复正是这个产品的重要价值之一。</p><h2 id="源码在哪里" tabindex="-1">源码在哪里？ <a class="header-anchor" href="#源码在哪里" aria-label="Permalink to &quot;源码在哪里？&quot;">​</a></h2><p>GitHub 首页: <a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></p>',13)])])}const u=e(i,[["render",l]]);export{m as __pageData,u as default};
